"use strict";(self.webpackChunkmotion_storybook=self.webpackChunkmotion_storybook||[]).push([[994],{"./src/benchmark/Atlaskit.stories.js"(__unused_webpack_module,__webpack_exports__,__webpack_require__){__webpack_require__.r(__webpack_exports__),__webpack_require__.d(__webpack_exports__,{AnimatedDemo:()=>AnimatedDemo,Signature:()=>Signature,TokenSet:()=>TokenSet,__namedExportsOrder:()=>__namedExportsOrder,default:()=>__WEBPACK_DEFAULT_EXPORT__});const __WEBPACK_DEFAULT_EXPORT__={title:"Benchmark/Atlaskit",parameters:{layout:"fullscreen",docs:{description:{component:"Atlassian Atlaskit — motion tokens. Standard duration scale and easing curves. Atlaskit represents a pragmatic, conventional approach — no novel naming conventions, no expressive/functional split. A useful baseline for cross-system comparison."}}}},baseStyles="\n  * { box-sizing: border-box; margin: 0; padding: 0; }\n  body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #f8f8f8; }\n  .page { max-width: 960px; margin: 0 auto; padding: 48px 32px; }\n  .sys-badge { display: inline-block; font-size: 11px; font-weight: 700; letter-spacing: 0.1em;\n    text-transform: uppercase; padding: 3px 10px; border-radius: 4px; margin-bottom: 8px;\n    background: #0052cc; color: #fff; }\n  .page-title { font-size: 22px; font-weight: 700; color: #111; margin-bottom: 6px; }\n  .page-desc { font-size: 14px; color: #555; line-height: 1.6; margin-bottom: 40px; max-width: 680px; }\n  .limited-data-banner { background: #fff9e6; border: 1px solid #f5a623; border-radius: 8px;\n    padding: 20px 24px; margin-bottom: 32px; }\n  .limited-data-title { font-size: 14px; font-weight: 700; color: #7a4a00; margin-bottom: 8px; }\n  .limited-data-body { font-size: 13px; color: #555; line-height: 1.6; }\n  .context-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 24px; margin-bottom: 40px; }\n  .context-card { background: #fff; border: 1px solid #e0e0e0; border-radius: 8px; padding: 20px; }\n  .context-card-title { font-size: 13px; font-weight: 700; color: #333; margin-bottom: 12px;\n    padding-bottom: 8px; border-bottom: 1px solid #f0f0f0; }\n  table { border-collapse: collapse; width: 100%; font-size: 12px; margin-bottom: 48px; }\n  th { text-align: left; padding: 8px 12px; font-size: 11px; font-weight: 600; color: #aaa;\n    text-transform: uppercase; letter-spacing: 0.08em; border-bottom: 2px solid #e4e4e4; }\n  td { padding: 9px 12px; border-bottom: 1px solid #f0f0f0; vertical-align: middle; }\n  td.mono { font-family: 'SF Mono', 'Fira Code', monospace; color: #333; font-size: 11px; }\n  .check { color: #007755; font-weight: 700; }\n  .cross { color: #999; }\n",TokenSet={name:"Token set",render:()=>{const el=document.createElement("div");return el.innerHTML=`\n      <style>${baseStyles}</style>\n      <div class="page">\n        <div class="sys-badge">Atlaskit</div>\n        <div class="page-title">Token set</div>\n        <div class="page-desc">\n          What is known from the benchmark research about Atlaskit's motion system.\n        </div>\n\n        <div class="limited-data-banner">\n          <div class="limited-data-title">Baseline system — concrete values not in research data</div>\n          <div class="limited-data-body">\n            The benchmark (May 2026) includes Atlaskit in the system parameters table but does not document\n            specific token values in its concrete values sections. Atlaskit's motion tokens are part of its\n            design system — the values were not captured in the public research at time of writing.\n            This story shows what is confirmed from the benchmark and marks specifics as pending.\n          </div>\n        </div>\n\n        <div class="context-grid">\n          <div class="context-card">\n            <div class="context-card-title">What the benchmark confirms</div>\n            <table style="margin-bottom:0;">\n              <thead><tr><th>Parameter</th><th>Status</th></tr></thead>\n              <tbody>\n                <tr><td>Duration tokens</td><td class="check">✓ present</td></tr>\n                <tr><td>Easing tokens</td><td class="check">✓ present</td></tr>\n                <tr><td>Spring tokens</td><td class="cross">— not documented</td></tr>\n                <tr><td>Keyframe tokens</td><td class="cross">— not documented</td></tr>\n                <tr><td>Stagger tokens</td><td class="cross">— not documented</td></tr>\n                <tr><td>Concrete values</td><td class="cross">— not in research data</td></tr>\n              </tbody>\n            </table>\n          </div>\n\n          <div class="context-card">\n            <div class="context-card-title">Role in benchmark</div>\n            <div style="font-size:13px;color:#555;line-height:1.6;">\n              <p>Atlaskit is included in the cross-system comparison table as one of the 9 systems surveyed.\n              It represents a conventional, pragmatic approach to motion tokens without novel\n              naming conventions or philosophical frameworks.</p>\n              <br>\n              <p>In the naming comparison table, Atlaskit is listed alongside other systems\n              as using standard duration and easing token patterns.</p>\n            </div>\n          </div>\n        </div>\n\n        <div style="background:#f0f8ff;border-radius:8px;padding:16px 20px;font-size:13px;color:#333;line-height:1.6;">\n          <strong>Benchmark role:</strong> Atlaskit serves as a useful baseline comparison point —\n          a system that implements duration + easing tokens without a functional/expressive split,\n          without spring tokens, and without directional encoding in names.\n          When all 9 systems are compared, systems like Atlaskit establish the "conventional" baseline\n          against which Carbon's function API, eBay's directional naming, and Apple's spring-first approach\n          can be measured.\n        </div>\n      </div>\n    `,el}},AnimatedDemo={name:"Animated demo",render:()=>{const durationOptions=[{name:"duration.short",value:100},{name:"duration.medium",value:200},{name:"duration.long",value:400}].map(d=>`<option value="${d.value}">${d.name} (${d.value}ms — illustrative)</option>`).join(""),easingOptions=[{name:"ease-in-out",curve:"cubic-bezier(0.42, 0, 0.58, 1)"},{name:"ease-out",curve:"cubic-bezier(0, 0, 0.4, 1)"},{name:"ease-in",curve:"cubic-bezier(0.5, 0, 1, 1)"}].map(e=>`<option value="${e.curve}">${e.name}</option>`).join(""),el=document.createElement("div");el.innerHTML=`\n      <style>\n        ${baseStyles}\n        .notice { background:#fff9e6;border:1px solid #f5a623;border-radius:6px;padding:12px 16px;\n          font-size:12px;color:#7a4a00;margin-bottom:24px; }\n        .controls { display: flex; gap: 12px; align-items: center; flex-wrap: wrap; margin-bottom: 32px; }\n        select { padding: 7px 10px; border: 1px solid #e0e0e0; border-radius: 4px;\n          font-family: inherit; font-size: 12px; background: #fff; min-width: 240px; }\n        .play-btn { padding: 8px 20px; background: #0052cc; color: #fff; border: none;\n          border-radius: 4px; font-size: 13px; font-weight: 600; cursor: pointer; font-family: inherit; }\n        .play-btn:disabled { opacity: 0.5; cursor: default; }\n        .stage { width: 280px; height: 80px; background: #e0ecff; border-radius: 6px;\n          position: relative; margin-bottom: 16px; }\n        .ref-box { width: 60px; height: 60px; background: #0052cc; border-radius: 6px;\n          position: absolute; left: 0; top: 10px; }\n        .labels { font-size: 11px; font-family: monospace; color: #555; line-height: 1.8; }\n      </style>\n      <div class="page">\n        <div class="sys-badge">Atlaskit</div>\n        <div class="page-title">Animated demo</div>\n        <div class="notice">\n          Illustrative values only — specific Atlaskit token values are not in the benchmark research data.\n          These durations and curves are shown for demonstration purposes.\n        </div>\n        <div class="controls">\n          <select id="durSel">${durationOptions}</select>\n          <select id="easSel">${easingOptions}</select>\n          <button class="play-btn" id="playBtn">Play</button>\n        </div>\n        <div class="stage"><div class="ref-box" id="box"></div></div>\n        <div class="labels" id="labels"></div>\n      </div>\n    `;const durSel=el.querySelector("#durSel"),easSel=el.querySelector("#easSel"),playBtn=el.querySelector("#playBtn"),box=el.querySelector("#box"),labels=el.querySelector("#labels");function updateLabels(){labels.textContent=`duration: ${durSel.value}ms (illustrative)   easing: ${easSel.value}`}return updateLabels(),durSel.addEventListener("change",updateLabels),easSel.addEventListener("change",updateLabels),playBtn.addEventListener("click",()=>{if(playBtn.disabled)return;playBtn.disabled=!0;const dur=parseInt(durSel.value,10);box.animate([{transform:"translateX(0px)"},{transform:"translateX(120px)"},{transform:"translateX(0px)"}],{duration:2*dur,easing:easSel.value,fill:"forwards"}).onfinish=()=>{playBtn.disabled=!1}}),el}},Signature={name:"Signature — conventional baseline",render:()=>{const el=document.createElement("div");return el.innerHTML=`\n      <style>\n        ${baseStyles}\n        .philosophy-table { margin-bottom: 32px; }\n        .baseline-row { background: #e8f0ff !important; }\n        .baseline-badge { display:inline-block; font-size:10px; padding:1px 6px;\n          background:#0052cc; color:#fff; border-radius:3px; font-weight:700; margin-left:6px; }\n        .explanation { background:#f0f8ff;border-left:3px solid #0052cc;padding:14px 16px;\n          border-radius:0 6px 6px 0;font-size:13px;color:#333;line-height:1.6; }\n      </style>\n      <div class="page">\n        <div class="sys-badge">Atlaskit</div>\n        <div class="page-title">Signature — Conventional baseline</div>\n        <div class="page-desc">\n          Atlaskit's value in this benchmark is as a reference point for what a "conventional" motion system\n          looks like — against which other systems' architectural choices can be measured.\n        </div>\n\n        <div class="limited-data-banner" style="background:#fff9e6;border:1px solid #f5a623;border-radius:8px;padding:16px 20px;margin-bottom:32px;">\n          <div style="font-size:13px;font-weight:700;color:#7a4a00;margin-bottom:6px;">Baseline system — concrete values not in research data</div>\n          <div style="font-size:13px;color:#555;line-height:1.6;">Specific Atlaskit token values were not captured in the benchmark research. This story focuses on Atlaskit's role as a baseline comparison point.</div>\n        </div>\n\n        <table class="philosophy-table">\n          <thead><tr><th>System</th><th>Naming / architectural approach</th></tr></thead>\n          <tbody>\n            ${[{system:"Atlaskit",approach:"Conventional: duration + easing, no novel conventions",badge:"#0052cc",baseline:!0},{system:"IBM Carbon",approach:"Function API: motion(type, mode) — intent at callsite",badge:"#0f62fe"},{system:"eBay Skin",approach:"Directional naming: quick.enter / quick.exit in token name",badge:"#e53238"},{system:"Uber Base",approach:"Weight rank scale: timing100 = 250ms (not 100ms)",badge:"#000"},{system:"Apple HIG",approach:"Spring-first: no durations, only response + bounce",badge:"#1c1c1e"},{system:"GitHub Primer",approach:"Composite tokens as primary API: motion.transition.enter",badge:"#0969da"}].map(s=>`\n              <tr class="${s.baseline?"baseline-row":""}">\n                <td>\n                  <span style="display:inline-block;padding:2px 8px;border-radius:4px;\n                    background:${s.badge};color:#fff;font-size:11px;font-weight:700;margin-right:6px;">\n                    ${s.system}\n                  </span>\n                  ${s.baseline?'<span class="baseline-badge">baseline</span>':""}\n                </td>\n                <td style="font-size:13px;color:#333;">${s.approach}</td>\n              </tr>\n            `).join("")}\n          </tbody>\n        </table>\n\n        <div class="explanation">\n          <strong>Why a baseline matters:</strong> The architectural novelty of Carbon's function API,\n          eBay's directional naming, and Uber's weight rank scale only becomes visible when compared\n          to a system that does none of those things. Atlaskit's conventional approach —\n          duration tokens + easing tokens, named in standard ways — establishes the floor.\n          Every other system in this benchmark has made at least one deliberate departure from\n          this pattern. Understanding what the departure is requires knowing what the default looks like.\n        </div>\n      </div>\n    `,el}},__namedExportsOrder=["TokenSet","AnimatedDemo","Signature"];TokenSet.parameters={...TokenSet.parameters,docs:{...TokenSet.parameters?.docs,source:{originalSource:'{\n  name: \'Token set\',\n  render: () => {\n    const el = document.createElement(\'div\');\n    el.innerHTML = `\n      <style>${baseStyles}</style>\n      <div class="page">\n        <div class="sys-badge">Atlaskit</div>\n        <div class="page-title">Token set</div>\n        <div class="page-desc">\n          What is known from the benchmark research about Atlaskit\'s motion system.\n        </div>\n\n        <div class="limited-data-banner">\n          <div class="limited-data-title">Baseline system — concrete values not in research data</div>\n          <div class="limited-data-body">\n            The benchmark (May 2026) includes Atlaskit in the system parameters table but does not document\n            specific token values in its concrete values sections. Atlaskit\'s motion tokens are part of its\n            design system — the values were not captured in the public research at time of writing.\n            This story shows what is confirmed from the benchmark and marks specifics as pending.\n          </div>\n        </div>\n\n        <div class="context-grid">\n          <div class="context-card">\n            <div class="context-card-title">What the benchmark confirms</div>\n            <table style="margin-bottom:0;">\n              <thead><tr><th>Parameter</th><th>Status</th></tr></thead>\n              <tbody>\n                <tr><td>Duration tokens</td><td class="check">✓ present</td></tr>\n                <tr><td>Easing tokens</td><td class="check">✓ present</td></tr>\n                <tr><td>Spring tokens</td><td class="cross">— not documented</td></tr>\n                <tr><td>Keyframe tokens</td><td class="cross">— not documented</td></tr>\n                <tr><td>Stagger tokens</td><td class="cross">— not documented</td></tr>\n                <tr><td>Concrete values</td><td class="cross">— not in research data</td></tr>\n              </tbody>\n            </table>\n          </div>\n\n          <div class="context-card">\n            <div class="context-card-title">Role in benchmark</div>\n            <div style="font-size:13px;color:#555;line-height:1.6;">\n              <p>Atlaskit is included in the cross-system comparison table as one of the 9 systems surveyed.\n              It represents a conventional, pragmatic approach to motion tokens without novel\n              naming conventions or philosophical frameworks.</p>\n              <br>\n              <p>In the naming comparison table, Atlaskit is listed alongside other systems\n              as using standard duration and easing token patterns.</p>\n            </div>\n          </div>\n        </div>\n\n        <div style="background:#f0f8ff;border-radius:8px;padding:16px 20px;font-size:13px;color:#333;line-height:1.6;">\n          <strong>Benchmark role:</strong> Atlaskit serves as a useful baseline comparison point —\n          a system that implements duration + easing tokens without a functional/expressive split,\n          without spring tokens, and without directional encoding in names.\n          When all 9 systems are compared, systems like Atlaskit establish the "conventional" baseline\n          against which Carbon\'s function API, eBay\'s directional naming, and Apple\'s spring-first approach\n          can be measured.\n        </div>\n      </div>\n    `;\n    return el;\n  }\n}',...TokenSet.parameters?.docs?.source}}},AnimatedDemo.parameters={...AnimatedDemo.parameters,docs:{...AnimatedDemo.parameters?.docs,source:{originalSource:"{\n  name: 'Animated demo',\n  render: () => {\n    // Using generic illustrative values since Atlaskit values are not in benchmark data\n    const illustrativeDurations = [{\n      name: 'duration.short',\n      value: 100\n    }, {\n      name: 'duration.medium',\n      value: 200\n    }, {\n      name: 'duration.long',\n      value: 400\n    }];\n    const illustrativeEasings = [{\n      name: 'ease-in-out',\n      curve: 'cubic-bezier(0.42, 0, 0.58, 1)'\n    }, {\n      name: 'ease-out',\n      curve: 'cubic-bezier(0, 0, 0.4, 1)'\n    }, {\n      name: 'ease-in',\n      curve: 'cubic-bezier(0.5, 0, 1, 1)'\n    }];\n    const durationOptions = illustrativeDurations.map(d => `<option value=\"${d.value}\">${d.name} (${d.value}ms — illustrative)</option>`).join('');\n    const easingOptions = illustrativeEasings.map(e => `<option value=\"${e.curve}\">${e.name}</option>`).join('');\n    const el = document.createElement('div');\n    el.innerHTML = `\n      <style>\n        ${baseStyles}\n        .notice { background:#fff9e6;border:1px solid #f5a623;border-radius:6px;padding:12px 16px;\n          font-size:12px;color:#7a4a00;margin-bottom:24px; }\n        .controls { display: flex; gap: 12px; align-items: center; flex-wrap: wrap; margin-bottom: 32px; }\n        select { padding: 7px 10px; border: 1px solid #e0e0e0; border-radius: 4px;\n          font-family: inherit; font-size: 12px; background: #fff; min-width: 240px; }\n        .play-btn { padding: 8px 20px; background: #0052cc; color: #fff; border: none;\n          border-radius: 4px; font-size: 13px; font-weight: 600; cursor: pointer; font-family: inherit; }\n        .play-btn:disabled { opacity: 0.5; cursor: default; }\n        .stage { width: 280px; height: 80px; background: #e0ecff; border-radius: 6px;\n          position: relative; margin-bottom: 16px; }\n        .ref-box { width: 60px; height: 60px; background: #0052cc; border-radius: 6px;\n          position: absolute; left: 0; top: 10px; }\n        .labels { font-size: 11px; font-family: monospace; color: #555; line-height: 1.8; }\n      </style>\n      <div class=\"page\">\n        <div class=\"sys-badge\">Atlaskit</div>\n        <div class=\"page-title\">Animated demo</div>\n        <div class=\"notice\">\n          Illustrative values only — specific Atlaskit token values are not in the benchmark research data.\n          These durations and curves are shown for demonstration purposes.\n        </div>\n        <div class=\"controls\">\n          <select id=\"durSel\">${durationOptions}</select>\n          <select id=\"easSel\">${easingOptions}</select>\n          <button class=\"play-btn\" id=\"playBtn\">Play</button>\n        </div>\n        <div class=\"stage\"><div class=\"ref-box\" id=\"box\"></div></div>\n        <div class=\"labels\" id=\"labels\"></div>\n      </div>\n    `;\n    const durSel = el.querySelector('#durSel');\n    const easSel = el.querySelector('#easSel');\n    const playBtn = el.querySelector('#playBtn');\n    const box = el.querySelector('#box');\n    const labels = el.querySelector('#labels');\n    function updateLabels() {\n      labels.textContent = `duration: ${durSel.value}ms (illustrative)   easing: ${easSel.value}`;\n    }\n    updateLabels();\n    durSel.addEventListener('change', updateLabels);\n    easSel.addEventListener('change', updateLabels);\n    playBtn.addEventListener('click', () => {\n      if (playBtn.disabled) return;\n      playBtn.disabled = true;\n      const dur = parseInt(durSel.value, 10);\n      box.animate([{\n        transform: 'translateX(0px)'\n      }, {\n        transform: 'translateX(120px)'\n      }, {\n        transform: 'translateX(0px)'\n      }], {\n        duration: dur * 2,\n        easing: easSel.value,\n        fill: 'forwards'\n      }).onfinish = () => {\n        playBtn.disabled = false;\n      };\n    });\n    return el;\n  }\n}",...AnimatedDemo.parameters?.docs?.source}}},Signature.parameters={...Signature.parameters,docs:{...Signature.parameters?.docs,source:{originalSource:"{\n  name: 'Signature — conventional baseline',\n  render: () => {\n    // Compare Atlaskit's role against other systems in the benchmark\n    const systemPhilosophies = [{\n      system: 'Atlaskit',\n      approach: 'Conventional: duration + easing, no novel conventions',\n      badge: '#0052cc',\n      baseline: true\n    }, {\n      system: 'IBM Carbon',\n      approach: 'Function API: motion(type, mode) — intent at callsite',\n      badge: '#0f62fe'\n    }, {\n      system: 'eBay Skin',\n      approach: 'Directional naming: quick.enter / quick.exit in token name',\n      badge: '#e53238'\n    }, {\n      system: 'Uber Base',\n      approach: 'Weight rank scale: timing100 = 250ms (not 100ms)',\n      badge: '#000'\n    }, {\n      system: 'Apple HIG',\n      approach: 'Spring-first: no durations, only response + bounce',\n      badge: '#1c1c1e'\n    }, {\n      system: 'GitHub Primer',\n      approach: 'Composite tokens as primary API: motion.transition.enter',\n      badge: '#0969da'\n    }];\n    const el = document.createElement('div');\n    el.innerHTML = `\n      <style>\n        ${baseStyles}\n        .philosophy-table { margin-bottom: 32px; }\n        .baseline-row { background: #e8f0ff !important; }\n        .baseline-badge { display:inline-block; font-size:10px; padding:1px 6px;\n          background:#0052cc; color:#fff; border-radius:3px; font-weight:700; margin-left:6px; }\n        .explanation { background:#f0f8ff;border-left:3px solid #0052cc;padding:14px 16px;\n          border-radius:0 6px 6px 0;font-size:13px;color:#333;line-height:1.6; }\n      </style>\n      <div class=\"page\">\n        <div class=\"sys-badge\">Atlaskit</div>\n        <div class=\"page-title\">Signature — Conventional baseline</div>\n        <div class=\"page-desc\">\n          Atlaskit's value in this benchmark is as a reference point for what a \"conventional\" motion system\n          looks like — against which other systems' architectural choices can be measured.\n        </div>\n\n        <div class=\"limited-data-banner\" style=\"background:#fff9e6;border:1px solid #f5a623;border-radius:8px;padding:16px 20px;margin-bottom:32px;\">\n          <div style=\"font-size:13px;font-weight:700;color:#7a4a00;margin-bottom:6px;\">Baseline system — concrete values not in research data</div>\n          <div style=\"font-size:13px;color:#555;line-height:1.6;\">Specific Atlaskit token values were not captured in the benchmark research. This story focuses on Atlaskit's role as a baseline comparison point.</div>\n        </div>\n\n        <table class=\"philosophy-table\">\n          <thead><tr><th>System</th><th>Naming / architectural approach</th></tr></thead>\n          <tbody>\n            ${systemPhilosophies.map(s => `\n              <tr class=\"${s.baseline ? 'baseline-row' : ''}\">\n                <td>\n                  <span style=\"display:inline-block;padding:2px 8px;border-radius:4px;\n                    background:${s.badge};color:#fff;font-size:11px;font-weight:700;margin-right:6px;\">\n                    ${s.system}\n                  </span>\n                  ${s.baseline ? '<span class=\"baseline-badge\">baseline</span>' : ''}\n                </td>\n                <td style=\"font-size:13px;color:#333;\">${s.approach}</td>\n              </tr>\n            `).join('')}\n          </tbody>\n        </table>\n\n        <div class=\"explanation\">\n          <strong>Why a baseline matters:</strong> The architectural novelty of Carbon's function API,\n          eBay's directional naming, and Uber's weight rank scale only becomes visible when compared\n          to a system that does none of those things. Atlaskit's conventional approach —\n          duration tokens + easing tokens, named in standard ways — establishes the floor.\n          Every other system in this benchmark has made at least one deliberate departure from\n          this pattern. Understanding what the departure is requires knowing what the default looks like.\n        </div>\n      </div>\n    `;\n    return el;\n  }\n}",...Signature.parameters?.docs?.source}}}}}]);
//# sourceMappingURL=benchmark-Atlaskit-stories.e2110404.iframe.bundle.js.map